vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    //ret = texture(sampler_main, vUv).xyz;
    ret1 = texture(sampler_rand00, vec2(vUv.x, vUv.y)).xyz;

    vec3 fire = texture(sampler_rand02, vec2(vUv.x+q4, vUv.y+q2)).xyz;
fire-=roam_sin*roam_cos.wzy;
    fire += texture(sampler_rand01, vec2(vUv.x+q5, vUv.y+q3)).xyz;
    fire += texture(sampler_rand01, vec2(vUv.x+q6, vUv.y+q1)).xyz;

    ret1 *= fire;

    ret1 *= (vUvOriginal.y + q11/2);

